import{_ as l,N as t,o as i,a as r,e as o,i as n}from"./chunks/framework.DW6Cm6Mn.js";const _=JSON.parse('{"title":"关于 Vala","description":"Vala 是一种面向对象的编程语言，具有自托管编译器，可生成 C 代码并使用 GObject 类型系统。","frontmatter":{"title":"关于 Vala","description":"Vala 是一种面向对象的编程语言，具有自托管编译器，可生成 C 代码并使用 GObject 类型系统。"},"headers":[],"relativePath":"zh_CN/about/index.md","filePath":"zh_CN/about/index.md"}'),d={name:"zh_CN/about/index.md"};function h(c,a,s,p,u,b){const e=t("PredefinedCtaStack");return i(),r("div",null,[a[0]||(a[0]=o('<h1 id="关于-vala" tabindex="-1">关于 Vala <a class="header-anchor" href="#关于-vala" aria-label="Permalink to &quot;关于 Vala&quot;">​</a></h1><h2 id="什么是-vala" tabindex="-1">什么是 Vala？ <a class="header-anchor" href="#什么是-vala" aria-label="Permalink to &quot;什么是 Vala？&quot;">​</a></h2><p>Vala 是一种面向对象的编程语言，具有自托管编译器，可生成 C 代码并使用 GObject 类型系统。</p><p>Vala 支持现代语言特性，例如：</p><ul><li>接口</li><li>属性</li><li>信号</li><li>Foreach 语句</li><li>Lambda 表达式</li><li>局部变量的类型推断</li><li>泛型</li><li>非空（Non-null）类型</li><li>辅助内存管理</li><li>异常处理</li><li>类型模块（插件）</li></ul><h2 id="vala-是什么语言" tabindex="-1">Vala 是什么语言？ <a class="header-anchor" href="#vala-是什么语言" aria-label="Permalink to &quot;Vala 是什么语言？&quot;">​</a></h2><h3 id="高效" tabindex="-1">高效 <a class="header-anchor" href="#高效" aria-label="Permalink to &quot;高效&quot;">​</a></h3><p>使用 Vala，您可以快速启动并运行，这要归功于 lambda 表达式、异常处理、接口和泛型等方便的功能。</p><h3 id="高性能" tabindex="-1">高性能 <a class="header-anchor" href="#高性能" aria-label="Permalink to &quot;高性能&quot;">​</a></h3><p>Vala 代码编译成完全原生的二进制文件。</p><h3 id="静态类型" tabindex="-1">静态类型 <a class="header-anchor" href="#静态类型" aria-label="Permalink to &quot;静态类型&quot;">​</a></h3><p>由于类型推断，Vala 可以帮助您编写类型安全的代码而不会冗长。</p><h3 id="整合" tabindex="-1">整合 <a class="header-anchor" href="#整合" aria-label="Permalink to &quot;整合&quot;">​</a></h3><p>Vala 旨在允许访问现有的 C 库，尤其是基于 GObject 的库，而无需运行时绑定。 使用带有 Vala 的库所需的全部是一个 API 文件，其中包含 Vala 语法中的类和方法声明。 Vala 当前附带了 GLib 和 GTK+ 以及 GNOME 平台的许多其他绑定。</p><p>Vala 也可以用来创建 C 库。</p><h3 id="熟悉" tabindex="-1">熟悉 <a class="header-anchor" href="#熟悉" aria-label="Permalink to &quot;熟悉&quot;">​</a></h3><p>Vala 的语法受到 C# 和 Java 的启发，因此如果您使用过其中任何一个，您将无缝地适应编写 Vala 代码。</p>',17)),n(e)])}const m=l(d,[["render",h]]);export{_ as __pageData,m as default};
